{
  "structure_appropriate": false,
  "issues": [
    {
      "issue": "Excessive and duplicate nav landmarks",
      "detail": "4 nav landmarks are present. Two share the same aria_label 'Menu' making them indistinguishable to assistive technology users, and two have no aria_label at all, leaving their purpose unclear.",
      "severity": "high"
    },
    {
      "issue": "Unlabelled nav landmarks",
      "detail": "2 of the 4 nav elements have no aria_label or aria_labelledby attribute. When multiple nav landmarks exist, each must have a unique, descriptive label so screen reader users can differentiate them.",
      "severity": "high"
    },
    {
      "issue": "Duplicate aria_label on nav landmarks",
      "detail": "Two separate nav elements both carry aria_label='Menu'. Identical labels on distinct landmarks cause confusion because assistive technologies will announce two landmarks with the same name.",
      "severity": "high"
    },
    {
      "issue": "Unlabelled search landmark",
      "detail": "The search landmark has no aria_label. While a single search landmark may be acceptable without a label, adding one improves clarity, especially alongside other unlabelled landmarks.",
      "severity": "low"
    },
    {
      "issue": "Structural imbalance — no header landmark",
      "detail": "A footer landmark is present but there is no corresponding header landmark. This asymmetry is unusual and may indicate a missing page header region.",
      "severity": "medium"
    }
